const CollectionCommand=require("./services/collectionCommand");async function testCollectionCommandSimple(){try{console.log("🧪 Testing Collection Command (Simple)..."),console.log("=".repeat(50));const testSlug="jooejoejoe",testChain="base";console.log(`🔍 Testing collection command for: ${testSlug}`),console.log(`📍 Chain: ${testChain}`),console.log("");const collectionCommand=new CollectionCommand,mockInteraction={options:{getString:name=>"slug"===name?testSlug:"chain"===name?testChain:null},deferReply:async()=>{console.log("⏳ Deferring reply...")},editReply:async content=>{if(console.log("✅ Reply sent:"),content.embeds&&content.embeds.length>0){const embed=content.embeds[0];console.log(`   Title: ${embed.title}`),console.log(`   Description: ${embed.description||"N/A"}`),embed.fields&&(console.log("   Fields:"),embed.fields.forEach((field=>{console.log(`     ${field.name}: ${field.value}`)})))}}};console.log("🚀 Executing collection command..."),await collectionCommand.execute(mockInteraction),console.log(""),console.log("✅ Collection command test completed successfully!")}catch(error){console.error("❌ Error:",error)}}testCollectionCommandSimple();